mapper.select:
SELECT COUNT(*) AS cnt
FROM (
    SELECT LS.PARTNO
    FROM TBL_PROD_STOCK SK
    JOIN TBL_PROD_LOTSTATE LS ON SK.LOTNO = LS.LOTNO
    LEFT JOIN TBL_COM_GOODS G ON LS.PARTNO = G.PARTNO
    LEFT JOIN TBL_COM_LOCATION LOC ON SK.LOCATIONCODE = LOC.LOCATIONCODE
    LEFT JOIN TBL_COM_WAREHOUSE WH ON LOC.WAREHOUSECODE = WH.WAREHOUSECODE

        SK.STOCKQTY > 0
        AND WH.PLANTCD = #{plant_cd}
        AND LOC.WAREHOUSECODE = #{warehouse_cd}
        AND LS.LINECD = #{line_cd}
        AND LS.PROCESSCD = #{process_cd}
        AND G.PARTTYPE = #{part_type}
        AND SK.LOTNO = #{lot_no}
        AND SK.LOCATIONCODE = #{location_cd}
        AND (LS.PARTNO LIKE #{search} OR G.PARTNM LIKE #{search})

    GROUP BY LS.PARTNO
) T
